#include<bits/stdc++.h>
using namespace std;
int a[11],v[1000010];
int main()
{
    int n,min1=INT_MAX,min2;
    scanf("%d",&n);
    for(int i=1;i<=9;i++)
    {
        scanf("%d",&a[i]);
        min1=min(min1,a[i]);
        if(a[i]==min1)
        {
            min2=i;
        }
    }
    int len=n/min1;
    int temp=n%min1;
    for(int i=1;i<=len;i++)
    {
        for(int j=9;j>=1;j--)
        {
            if(temp>=a[j]-min1)
            {
                temp-=a[j]-min1;
                v[i]=j;
                break;
            }
        }
        if(v[i]==0)
        {
            printf("%d",min2);
        }
        else
        {
            printf("%d",v[i]);
        }
    }
    return 0;
}
